Here's how to handle each scenario with MSTest:

### 1. Platform-specific (Windows only)

```csharp
// MSTest v3+: Use conditional skip via OSCondition
[TestMethod]
[SupportedOSPlatform("windows")]  // Compiler hint only — won't skip

// Preferred: dynamic skip with a guard
[TestMethod]
public void Registry_ReadsExpectedValue()
{
    if (!OperatingSystem.IsWindows())
        Assert.Inconclusive("Requires Windows registry.");

    // ... test logic
}
```

### 2. Skip in CI (requires local GPU)

```csharp
[TestMethod]
public void Render_ProducesExpectedFrame()
{
    if (Environment.GetEnvironmentVariable("CI") is not null)
        Assert.Inconclusive("Skipped in CI — requires local GPU.");

    // ... GPU test logic
}

// Or define a reusable attribute (MSTest v3.8+):
[AttributeUsage(AttributeTargets.Method, AllowMultiple = false)]
public class SkipInCIAttribute : TestMethodAttribute
{
    public override TestResult[] Execute(ITestMethod testMethod)
    {
        if (Environment.GetEnvironmentVariable("CI") is not null)
            return [new TestResult { Outcome = UnitTestOutcome.Inconclusive,
                                     TestFailureException = new AssertInconclusiveException(
                                         "Skipped in CI — requires local GPU.") }];
        return base.Execute(testMethod);
    }
}

[SkipInCI]
public void Render_ProducesExpectedFrame() { /* ... */ }
```

### 3. Flaky external API (retry)

```csharp
// Custom retry attribute
[AttributeUsage(AttributeTargets.Method)]
public class RetryAttribute : TestMethodAttribute
{
    private readonly int _maxAttempts;
    public RetryAttribute(int maxAttempts = 3) => _maxAttempts = maxAttempts;

    public override TestResult[] Execute(ITestMethod testMethod)
    {
        TestResult[]? results = null;
        for (int i = 0; i < _maxAttempts; i++)
        {
            results = base.Execute(testMethod);
            if (results.All(r => r.Outcome == UnitTestOutcome.Passed))
                return results;
        }
        return results!;
    }
}

[Retry(maxAttempts: 3)]
public void WeatherApi_ReturnsForecast() { /* ... */ }
```

### 4. Cleanup even on failure (temp files)

```csharp
// Option A: TestCleanup — runs after every test, even on failure
[TestClass]
public class FileProcessorTests
{
    private string _tempFile = null!;

    [TestInitialize]
    public void Setup() =>
        _tempFile = Path.GetTempFileName();

    [TestCleanup]
    public void Cleanup()
    {
        if (File.Exists(_tempFile))
            File.Delete(_tempFile);
    }

    [TestMethod]
    public void Process_WritesExpectedOutput()
    {
        File.WriteAllText(_tempFile, "data");
        // ... even if this throws, Cleanup still runs
    }
}

// Option B: AssemblyCleanup for broad resource teardown
[AssemblyCleanup]
public static void GlobalCleanup() =>
    Directory.Delete(TestTempDir, recursive: true);
```

**Key takeaways:**

| Scenario | Mechanism |
|---|---|
| Platform skip | `Assert.Inconclusive()` with OS guard |
| CI skip | Env-var check or custom `TestMethodAttribute` |
| Flaky retry | Custom `TestMethodAttribute` overriding `Execute` |
| Guaranteed cleanup | `[TestCleanup]` (always runs, even on failure) |

`Assert.Inconclusive` is preferred over `[Ignore]` for conditional skips because it evaluates at runtime and still shows in results, while `[Ignore]` is unconditional and silent.
